-- 现在为这些新用户分配用户角色（User角色，ID为2）
-- 首先获取刚才插入的用户ID范围
-- 我们假设之前的用户最大ID是2，新用户从3开始到102

INSERT OR IGNORE INTO UserRoles (UserId, RoleId)
SELECT Id, 2 FROM Users WHERE Username LIKE 'user%';

-- 验证数据
SELECT '=== 新增用户统计 ===' AS info;
SELECT COUNT(*) AS total_new_users FROM Users WHERE Username LIKE 'user%';

SELECT '=== 前10个新增用户 ===' AS info;
SELECT Id, Username, Email, DepartmentId, CreatedAt FROM Users WHERE Username LIKE 'user%' ORDER BY Id LIMIT 10;

SELECT '=== 用户角色分配统计 ===' AS info;
SELECT COUNT(*) AS users_with_roles FROM UserRoles WHERE UserId IN (SELECT Id FROM Users WHERE Username LIKE 'user%');
